#include <bits/stdc++.h>
using namespace std;

const int N=102,mod=1e9+7;

int n,a[N][N],ans[N][N],base[N][N],tmp[N][N];
long long k;

int main(){
    scanf("%d%lld",&n,&k);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)
            scanf("%d",&a[i][j]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)
            ans[i][j]=(i==j),base[i][j]=a[i][j];
    while(k){
        if(k&1){
            for(int i=1;i<=n;i++)
                for(int j=1;j<=n;j++)
                    tmp[i][j]=ans[i][j],ans[i][j]=0;
            for(int i=1;i<=n;i++)
                for(int j=1;j<=n;j++)
                    for(int k=1;k<=n;k++)
                        ans[i][j]=(ans[i][j]+1LL*tmp[i][k]*base[k][j])%mod;
        }
        for(int i=1;i<=n;i++)
            for(int j=1;j<=n;j++)
                tmp[i][j]=base[i][j],base[i][j]=0;
        for(int i=1;i<=n;i++)
            for(int j=1;j<=n;j++)
                for(int k=1;k<=n;k++)
                    base[i][j]=(base[i][j]+1LL*tmp[i][k]*tmp[k][j])%mod;
        k>>=1;
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++)
            printf("%d ",ans[i][j]);
        puts("");
    }
    return 0;
}
